export default function DivisionTabs({ divisions, selectedDiv, onSelect }) {
  return (
    <div className="flex flex-wrap gap-2 p-1.5 bg-zinc-900/50 rounded-2xl border border-zinc-800/60 backdrop-blur-sm">
      {Object.keys(divisions).map((key) => {
        const div = divisions[key];
        const isSelected = selectedDiv === key;
        const isNu = key.includes("nu");
        return (
          <button
            key={key}
            onClick={() => onSelect(key)}
            className={`relative px-4 py-2 rounded-xl text-xs font-mono font-bold transition-all duration-200 ${
              isSelected
                ? isNu
                  ? "bg-amber-500 text-zinc-950 shadow-lg shadow-amber-500/20"
                  : "bg-red-600 text-white shadow-lg shadow-red-600/25"
                : "text-zinc-500 hover:text-zinc-300 hover:bg-zinc-800/60"
            }`}
          >
            {div.weightClass}
            {isSelected && (
              <span className="absolute -top-1 -right-1 w-2 h-2 rounded-full bg-white animate-pulse" />
            )}
          </button>
        );
      })}
    </div>
  );
}
