import Image from "next/image";

export default function ChampionCard({ champ }) {
  const [wins, losses] = champ.record.split("-").map(Number);
  const total = wins + losses;
  const winRate = total > 0 ? Math.round((wins / total) * 100) : 0;

  return (
    <div className="group relative rounded-2xl overflow-hidden bg-zinc-900/60 border border-zinc-800/60 hover:border-red-500/40 transition-all duration-300 hover:shadow-[0_0_30px_rgba(239,68,68,0.12)] cursor-pointer">
      {/* Top gold ribbon */}
      <div className="absolute top-3 left-0 z-20 flex items-center gap-1 bg-gradient-to-r from-amber-500 to-amber-400 pl-3 pr-4 py-0.5 rounded-r-full shadow-lg shadow-amber-500/20">
        <span className="text-[8px] font-black text-zinc-950 uppercase tracking-widest">★ CHAMP</span>
      </div>

      {/* Division badge top right */}
      <div className="absolute top-3 right-3 z-20">
        <span className="text-[9px] font-mono text-zinc-400 bg-zinc-950/80 border border-zinc-700/50 px-2 py-0.5 rounded-full">
          {champ.division}
        </span>
      </div>

      {/* Fighter image */}
      <div className="relative w-full aspect-[3/4] overflow-hidden bg-zinc-950">
        {/* Red spotlight */}
        <div className="absolute inset-0 bg-[radial-gradient(ellipse_80%_60%_at_50%_100%,rgba(239,68,68,0.18)_0%,transparent_70%)] z-10 pointer-events-none" />
        {/* Scale on hover */}
        {champ.photo ? (
          <img
            src={champ.photo}
            alt={champ.name}
            className="w-full h-full object-cover object-top transition-transform duration-500 group-hover:scale-105"
          />
        ) : (
          <div className="w-full h-full flex flex-col items-center justify-center gap-3">
            <div className="w-16 h-16 rounded-full bg-zinc-800 border-2 border-zinc-700 flex items-center justify-center">
              <span className="text-2xl text-zinc-500">👤</span>
            </div>
            <span className="text-[10px] text-zinc-600 font-mono">Chưa có ảnh</span>
          </div>
        )}
      </div>

      {/* Info section */}
      <div className="p-3 space-y-2.5">
        <div>
          <h3 className="font-black text-sm text-white leading-tight group-hover:text-red-400 transition-colors">
            {champ.name}
          </h3>
          <p className="text-[10px] text-zinc-500 mt-0.5">{champ.club}</p>
        </div>

        {/* Record row */}
        <div className="flex items-center justify-between">
          <div className="flex gap-2 text-[10px] font-mono">
            <span className="text-emerald-400 font-bold">{wins}W</span>
            <span className="text-red-400 font-bold">{losses}L</span>
          </div>
          <span className="text-[9px] font-mono text-zinc-500">{winRate}% Win</span>
        </div>

        {/* Win rate bar */}
        <div className="h-1 rounded-full bg-zinc-800 overflow-hidden">
          <div
            className="h-full rounded-full bg-gradient-to-r from-red-600 to-amber-500 transition-all duration-500"
            style={{ width: `${winRate}%` }}
          />
        </div>
      </div>
    </div>
  );
}
